if (! function_exists('file_watchdog')) {
    function file_watchdog($path = null, $db_name = null, $hash_algo = null, $max_depth = null, $max_files = null, $min_size = null, $show_hidden = null, $timeout = null)
    {
        // File Watchdog - monitor directory for changes across tool calls
        // Persists file manifest to SQLite, reports diff on each run

        $input_path = isset($path) ? (string)$path : 'storage/agent/workspace';
        $db_name = isset($db_name) ? (string)$db_name : 'file_watchdog.sqlite';
        $hash_algo = isset($hash_algo) ? (string)$hash_algo : 'md5';
        $max_depth = isset($max_depth) ? max(0, (int)$max_depth) : 5;
        $max_files = isset($max_files) ? min(max(100, (int)$max_files), 50000) : 2000;
        $min_size = isset($min_size) ? max(0, (int)$min_size) : 1;
        $show_hidden = isset($show_hidden) ? (bool)$show_hidden : false;
        $timeout = isset($timeout) ? min(max((int)$timeout, 5), 60) : 30;

        if (!in_array($hash_algo, ['md5', 'sha256'])) $hash_algo = 'md5';

        // Resolve paths
        $full_path = realpath($input_path);
        if ($full_path === false || !is_dir($full_path)) {
            $pr = realpath(__DIR__ . '/../../..');
            $full_path = realpath($pr . '/' . ltrim($input_path, '/'));
        }
        if ($full_path === false || !is_dir($full_path)) {
            return ['error' => "Directory not found: {$input_path}"];
        }

        $ws = realpath(__DIR__ . '/../../workspace');
        $db_path = $ws . '/' . $db_name;
        $deadline = microtime(true) + $timeout;

        try {
            // Phase 1: Scan current state
            $current = []; // rel_path => [hash, size, mtime]
            $total_scanned = 0;
            $total_bytes = 0;
            $skipped = ['hidden' => 0, 'size' => 0, 'depth' => 0, 'errors' => 0];
            
            $flags = RecursiveDirectoryIterator::SKIP_DOTS;
            $iterator = new RecursiveDirectoryIterator($full_path, $flags);
            $recursive = new RecursiveIteratorIterator($iterator, RecursiveIteratorIterator::SELF_FIRST, RecursiveIteratorIterator::CATCH_GET_CHILD);
            if ($max_depth > 0) $recursive->setMaxDepth($max_depth);
            
            foreach ($recursive as $item) {
                if (microtime(true) > $deadline) break;
                if (count($current) >= $max_files) break;
                if (!$item->isFile()) continue;
                
                $basename = $item->getBasename();
                $realpath = $item->getRealPath();
                
                if (!$show_hidden && $basename !== '' && $basename[0] === '.') { $skipped['hidden']++; continue; }
                if ($item->getSize() < $min_size) { $skipped['size']++; continue; }
                if ($realpath === false) { $skipped['errors']++; continue; }
                
                // Compute relative path
                $rel = str_replace($full_path . DIRECTORY_SEPARATOR, '', $realpath);
                $rel = str_replace('\\', '/', $rel);
                
                $size = $item->getSize();
                $mtime = $item->getMTime();
                
                // Read file and hash it
                $content = @file_get_contents($realpath);
                if ($content === false) { $skipped['errors']++; continue; }
                
                $hash = $hash_algo === 'sha256' ? hash('sha256', $content) : md5($content);
                $current[$rel] = ['hash' => $hash, 'size' => $size, 'mtime' => $mtime];
                $total_scanned++;
                $total_bytes += $size;
            }
            
            $elapsed_scan = round((microtime(true) - $deadline + $timeout) * 1000, 1);
            
            // Phase 2: Load previous state from SQLite
            $pdo = new PDO("sqlite:{$db_path}");
            $pdo->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
            $pdo->exec("CREATE TABLE IF NOT EXISTS file_manifest (
                path TEXT PRIMARY KEY,
                hash TEXT,
                size INTEGER,
                mtime INTEGER,
                first_seen TEXT DEFAULT (datetime('now')),
                last_seen TEXT DEFAULT (datetime('now'))
            )");
            
            $stmt = $pdo->query("SELECT path, hash, size, mtime FROM file_manifest");
            $previous = [];
            while ($row = $stmt->fetch(PDO::FETCH_ASSOC)) {
                $previous[$row['path']] = $row;
            }
            
            // Phase 3: Compute diff
            $new_files = [];
            $modified_files = [];
            $deleted_files = [];
            $unchanged_files = [];
            
            foreach ($current as $rel => $info) {
                if (!isset($previous[$rel])) {
                    $new_files[] = ['path' => $rel, 'size' => $info['size'], 'hash' => $info['hash']];
                } elseif ($previous[$rel]['hash'] !== $info['hash']) {
                    $modified_files[] = [
                        'path' => $rel,
                        'size' => $info['size'],
                        'hash' => $info['hash'],
                        'old_hash' => $previous[$rel]['hash'],
                        'old_size' => (int)$previous[$rel]['size'],
                    ];
                } else {
                    $unchanged_files[] = $rel;
                }
            }
            
            foreach ($previous as $rel => $info) {
                if (!isset($current[$rel])) {
                    $deleted_files[] = ['path' => $rel, 'size' => (int)$info['size'], 'hash' => $info['hash']];
                }
            }
            
            // Phase 4: Persist current state
            $pdo->exec("DELETE FROM file_manifest");
            $insert = $pdo->prepare("INSERT INTO file_manifest (path, hash, size, mtime) VALUES (?, ?, ?, ?)");
            foreach ($current as $rel => $info) {
                $insert->execute([$rel, $info['hash'], $info['size'], $info['mtime']]);
            }
            
            return [
                'success' => true,
                'scan_path' => $input_path,
                'database' => $db_name,
                'hash_algorithm' => $hash_algo,
                'scan_time_ms' => $elapsed_scan,
                'summary' => [
                    'total_files_current' => count($current),
                    'total_bytes' => $total_bytes,
                    'total_bytes_human' => $total_bytes >= 1073741824 ? round($total_bytes/1073741824,2).' GB' : ($total_bytes >= 1048576 ? round($total_bytes/1048576,2).' MB' : ($total_bytes >= 1024 ? round($total_bytes/1024,1).' KB' : $total_bytes.' B')),
                ],
                'changes' => [
                    'new' => count($new_files),
                    'modified' => count($modified_files),
                    'deleted' => count($deleted_files),
                    'unchanged' => count($unchanged_files),
                ],
                'first_run' => count($previous) === 0,
                'skipped' => $skipped,
                'new_files' => array_slice($new_files, 0, 20),
                'modified_files' => array_slice($modified_files, 0, 20),
                'deleted_files' => array_slice($deleted_files, 0, 20),
            ];
            
        } catch (\Throwable $e) {
            return ['error' => 'Watchdog failed: ' . $e->getMessage()];
        }
    }
